```class Solution {
public:
    string reverseWords(string s) {
        string res = "";
        string temp = "";
        for(int i = s.length() - 1; i >= 0; i--) {
            if(s[i] != ' ') {
                temp = s[i] + temp;
            } else if(temp != "") {
                res = temp + " " + res;
                temp = "";
            }
        }
        if(temp != "") {
            res = temp + " " + res;
        }
        return res.substr(0, res.length() - 1);
    }
};```
